// apps/web/components/layout/main-layout.tsx
'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { useSession, signOut } from 'next-auth/react';
// import { cn } from '@thesis-review/ui/lib/utils';
// import { Button } from '@thesis-review/ui/components/button';
// import { Avatar, AvatarFallback, AvatarImage } from '@thesis-review/ui/components/avatar';
// import {
//   DropdownMenu,
//   DropdownMenuContent,
//   DropdownMenuItem,
//   DropdownMenuLabel,
//   DropdownMenuSeparator,
//   DropdownMenuTrigger,
// } from '@thesis-review/ui/components/dropdown-menu';
// import {
//   Sheet,
//   SheetContent,
//   SheetTrigger,
// } from '@thesis-review/ui/components/sheet';
// import {
//   LayoutDashboard,
//   FileUp,
//   FileText,
//   Users,
//   BarChart3,
//   Settings,
//   Bell,
//   Menu,
//   LogOut,
//   User,
//   ChevronDown,
//   Brain,
//   FolderOpen,
// } from 'lucide-react';

const navigation = {
  student: [
    { name: 'Dashboard', href: '/dashboard', icon: LayoutDashboard },
    { name: 'Subir Avance', href: '/upload', icon: FileUp },
    { name: 'Mis Documentos', href: '/my-documents', icon: FolderOpen },
    { name: 'Estadísticas', href: '/statistics', icon: BarChart3 },
  ],
  advisor: [
    { name: 'Dashboard', href: '/dashboard', icon: LayoutDashboard },
    { name: 'Revisar Avances', href: '/review', icon: FileText },
    { name: 'Mis Estudiantes', href: '/students', icon: Users },
    { name: 'Estadísticas', href: '/statistics', icon: BarChart3 },
  ],
  coordinator: [
    { name: 'Dashboard', href: '/dashboard', icon: LayoutDashboard },
    { name: 'Revisar Avances', href: '/review', icon: FileText },
    { name: 'Revisión por Lotes', href: '/bulk-review', icon: FolderOpen },
    { name: 'Estadísticas', href: '/statistics', icon: BarChart3 },
    { name: 'Documentos Patrón', href: '/templates', icon: FileText },
    { name: 'Configuración', href: '/settings', icon: Settings },
  ],
  admin: [
    { name: 'Dashboard', href: '/dashboard', icon: LayoutDashboard },
    { name: 'Usuarios', href: '/users', icon: Users },
    { name: 'Estadísticas', href: '/statistics', icon: BarChart3 },
    { name: 'Configuración', href: '/settings', icon: Settings },
    { name: 'IA Engine', href: '/ai-config', icon: Brain },
  ],
};

export function MainLayout({ children }: { children: React.ReactNode }) {
  const { data: session } = useSession();
  const pathname = usePathname();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const userRole = session?.user?.role?.toLowerCase() || 'student';
  const navItems = navigation[userRole as keyof typeof navigation] || navigation.student;

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  const getRoleLabel = (role: string) => {
    const labels: Record<string, string> = {
      STUDENT: 'Estudiante',
      ADVISOR: 'Asesor',
      COORDINATOR: 'Coordinador',
      ADMIN: 'Administrador',
    };
    return labels[role] || role;
  };

  return (
    <div className="min-h-screen bg-background">
      {/* Sidebar - Desktop */}
      <aside className="fixed inset-y-0 left-0 z-50 hidden w-64 border-r bg-card lg:block">
        <div className="flex h-full flex-col">
          {/* Logo */}
          <div className="flex h-16 items-center gap-2 border-b px-6">
            <Brain className="h-6 w-6 text-primary" />
            <span className="text-lg font-bold">ThesisReview</span>
            <span className="text-xs text-muted-foreground">v2.0</span>
          </div>

          {/* Navigation */}
          <nav className="flex-1 space-y-1 p-4">
            <div className="mb-4">
              <p className="px-3 text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                Principal
              </p>
            </div>
            {navItems.slice(0, 3).map((item) => {
              const isActive = pathname === item.href;
              return (
                <Link
                  key={item.name}
                  href={item.href}
                  className={cn(
                    'flex items-center gap-3 rounded-lg px-3 py-2 text-sm font-medium transition-colors',
                    isActive
                      ? 'bg-primary text-primary-foreground'
                      : 'text-muted-foreground hover:bg-muted hover:text-foreground'
                  )}
                >
                  <item.icon className="h-4 w-4" />
                  {item.name}
                </Link>
              );
            })}

            {navItems.length > 3 && (
              <>
                <div className="mb-4 mt-6">
                  <p className="px-3 text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                    Análisis
                  </p>
                </div>
                {navItems.slice(3).map((item) => {
                  const isActive = pathname === item.href;
                  return (
                    <Link
                      key={item.name}
                      href={item.href}
                      className={cn(
                        'flex items-center gap-3 rounded-lg px-3 py-2 text-sm font-medium transition-colors',
                        isActive
                          ? 'bg-primary text-primary-foreground'
                          : 'text-muted-foreground hover:bg-muted hover:text-foreground'
                      )}
                    >
                      <item.icon className="h-4 w-4" />
                      {item.name}
                    </Link>
                  );
                })}
              </>
            )}
          </nav>

          {/* User info bottom */}
          <div className="border-t p-4">
            <div className="flex items-center gap-3 rounded-lg bg-muted/50 p-3">
              <Avatar className="h-8 w-8">
                <AvatarImage src={session?.user?.avatarUrl || ''} />
                <AvatarFallback className="text-xs">
                  {getInitials(session?.user?.name || 'U')}
                </AvatarFallback>
              </Avatar>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium truncate">
                  {session?.user?.name}
                </p>
                <p className="text-xs text-muted-foreground">
                  {getRoleLabel(session?.user?.role || 'STUDENT')}
                </p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Mobile header */}
      <div className="sticky top-0 z-40 flex h-16 items-center gap-4 border-b bg-background px-4 lg:hidden">
        <Sheet open={sidebarOpen} onOpenChange={setSidebarOpen}>
          <SheetTrigger asChild>
            <Button variant="ghost" size="icon">
              <Menu className="h-5 w-5" />
            </Button>
          </SheetTrigger>
          <SheetContent side="left" className="w-64 p-0">
            <div className="flex h-full flex-col">
              <div className="flex h-16 items-center gap-2 border-b px-6">
                <Brain className="h-6 w-6 text-primary" />
                <span className="text-lg font-bold">ThesisReview</span>
              </div>
              <nav className="flex-1 space-y-1 p-4">
                {navItems.map((item) => {
                  const isActive = pathname === item.href;
                  return (
                    <Link
                      key={item.name}
                      href={item.href}
                      onClick={() => setSidebarOpen(false)}
                      className={cn(
                        'flex items-center gap-3 rounded-lg px-3 py-2 text-sm font-medium transition-colors',
                        isActive
                          ? 'bg-primary text-primary-foreground'
                          : 'text-muted-foreground hover:bg-muted hover:text-foreground'
                      )}
                    >
                      <item.icon className="h-4 w-4" />
                      {item.name}
                    </Link>
                  );
                })}
              </nav>
            </div>
          </SheetContent>
        </Sheet>

        <div className="flex-1">
          <Brain className="h-6 w-6 text-primary" />
        </div>

        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon">
              <Bell className="h-5 w-5" />
            </Button>
          </DropdownMenuTrigger>
        </DropdownMenu>

        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" className="relative h-8 w-8 rounded-full">
              <Avatar className="h-8 w-8">
                <AvatarImage src={session?.user?.avatarUrl || ''} />
                <AvatarFallback className="text-xs">
                  {getInitials(session?.user?.name || 'U')}
                </AvatarFallback>
              </Avatar>
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuLabel>
              <div className="flex flex-col space-y-1">
                <p className="text-sm font-medium">{session?.user?.name}</p>
                <p className="text-xs text-muted-foreground">{session?.user?.email}</p>
              </div>
            </DropdownMenuLabel>
            <DropdownMenuSeparator />
            <DropdownMenuItem asChild>
              <Link href="/profile">
                <User className="mr-2 h-4 w-4" />
                Perfil
              </Link>
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={() => signOut()}>
              <LogOut className="mr-2 h-4 w-4" />
              Cerrar sesión
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>

      {/* Main content */}
      <main className="lg:pl-64">
        {children}
      </main>
    </div>
  );
}